import { ChangeDetectionStrategy, Component } from '@angular/core';

import { NgIcon, provideIcons } from '@ng-icons/core';
import { phosphorPlus } from '@ng-icons/phosphor-icons/regular';

import { HbButtonComponent } from '@herbst/ui';

@Component({
  selector: 'hb-demo-button-sizes',
  imports: [HbButtonComponent, NgIcon],
  providers: [provideIcons({ phosphorPlus })],
  template: `
    <div class="flex flex-wrap items-center gap-2">
      <button hb-button hbSize="xs">Extra small</button>
      <button hb-button hbSize="sm">Small</button>
      <button hb-button hbSize="default">Default</button>
      <button hb-button hbSize="lg">Large</button>
      <button hb-button hbSize="xl">Extra large</button>
      <button hb-button hbSize="icon" aria-label="Add">
        <ng-icon name="phosphorPlus" />
      </button>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoButtonSizesComponent {}

import { ChangeDetectionStrategy, Component } from '@angular/core';

import { HbButtonComponent } from '@herbst/ui';

@Component({
  selector: 'hb-demo-button-states',
  imports: [HbButtonComponent],
  template: `
    <div class="flex w-full max-w-sm flex-col gap-3">
      <div class="flex flex-wrap items-center gap-2">
        <button hb-button hbDisabled>Disabled</button>
        <button hb-button hbLoading>Loading</button>
        <button hb-button hbType="outline" hbLoading>Saving</button>
        <a hb-button hbType="link" href="#" (click)="$event.preventDefault()">Anchor button</a>
      </div>

      <button hb-button hbFull>Full width</button>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoButtonStatesComponent {}

import { ChangeDetectionStrategy, Component } from '@angular/core';

import { HbButtonComponent } from '@herbst/ui';

@Component({
  selector: 'hb-demo-button-types',
  imports: [HbButtonComponent],
  template: `
    <div class="flex flex-wrap items-center gap-2">
      <button hb-button>Default</button>
      <button hb-button hbType="secondary">Secondary</button>
      <button hb-button hbType="outline">Outline</button>
      <button hb-button hbType="ghost">Ghost</button>
      <button hb-button hbType="success">Success</button>
      <button hb-button hbType="warning">Warning</button>
      <button hb-button hbType="destructive">Destructive</button>
      <button hb-button hbType="link">Link</button>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoButtonTypesComponent {}
